const assets = {"/index.html":{"contentType":"text/html; charset=utf-8","body":"<!doctype html>\n<html lang=\"es\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title>Lagomarsino S.A. - Mapa Comercial Embolsado</title>\n    <link rel=\"stylesheet\" href=\"/styles.css?v=20260618-7\" />\n  </head>\n  <body>\n    <main class=\"app-shell\">\n      <section class=\"map-stage\" aria-label=\"Mapa comercial Embolsado\">\n        <div id=\"map\"></div>\n        <div class=\"map-topbar\">\n          <div class=\"brand-block\">\n            <p>Lagomarsino S.A. / Canal Embolsado</p>\n            <h1>Mapa Comercial</h1>\n          </div>\n          <div class=\"map-actions\" aria-label=\"Acciones del mapa\">\n            <button id=\"fit-map\" class=\"icon-button\" type=\"button\" title=\"Ver AMBA\">⌖</button>\n            <button id=\"toggle-edit\" class=\"text-button\" type=\"button\">Editar zonas</button>\n          </div>\n        </div>\n      </section>\n\n      <aside class=\"control-panel\" aria-label=\"Panel territorial\">\n        <section class=\"panel-section\">\n          <div class=\"section-heading\">\n            <span>Zonas tentativas</span>\n            <strong>4</strong>\n          </div>\n          <div id=\"zone-filters\" class=\"filter-list\"></div>\n        </section>\n\n        <section class=\"panel-section\">\n          <label class=\"select-label\" for=\"zone-editor-select\">Zona a editar</label>\n          <select id=\"zone-editor-select\"></select>\n          <div class=\"hint\">\n            Arrastra vertices en el mapa o pega coordenadas JSON. Despues copia la configuracion para conservar los cambios.\n          </div>\n        </section>\n\n        <section class=\"panel-section editor-panel\">\n          <div class=\"section-heading compact\">\n            <span>Coordenadas</span>\n            <button id=\"apply-coordinates\" class=\"text-button muted\" type=\"button\">Aplicar</button>\n          </div>\n          <textarea id=\"coordinates-editor\" spellcheck=\"false\"></textarea>\n          <div id=\"editor-status\" class=\"editor-status\">Editor listo.</div>\n        </section>\n\n        <section class=\"panel-section\">\n          <div class=\"section-heading compact\">\n            <span>Capas</span>\n          </div>\n          <label class=\"switch-row\">\n            <input id=\"toggle-caba\" type=\"checkbox\" checked />\n            <span>Mostrar Capital Federal excluida</span>\n          </label>\n          <label class=\"switch-row\">\n            <input id=\"toggle-reference\" type=\"checkbox\" checked />\n            <span>Mostrar puntos de referencia</span>\n          </label>\n        </section>\n\n        <section class=\"panel-section summary-panel\">\n          <div class=\"metric-row\">\n            <span>Clientes</span>\n            <strong>pendiente Excel</strong>\n          </div>\n          <div class=\"metric-row\">\n            <span>Ventas</span>\n            <strong>no cargadas</strong>\n          </div>\n          <div class=\"metric-row\">\n            <span>CABA</span>\n            <strong>excluida</strong>\n          </div>\n        </section>\n\n        <div class=\"panel-footer\">\n          <button id=\"copy-config\" class=\"primary-button\" type=\"button\">Copiar zonas JSON</button>\n          <p>Primera version territorial: AMBA sin Capital Federal e Interior. Preparada para sumar clientes geolocalizados y ventas mas adelante.</p>\n        </div>\n      </aside>\n    </main>\n\n    <script\n      src=\"https://unpkg.com/leaflet@1.9.4/dist/leaflet.js\"\n      integrity=\"sha256-20nQCchB9co0qIjJZRGuk2/Z9VM+kNiyxNV1lvTlZBo=\"\n      crossorigin=\"\"\n    ></script>\n    <script src=\"/data.js?v=20260618-7\"></script>\n    <script src=\"/app.js?v=20260618-7\"></script>\n  </body>\n</html>\n"},"/styles.css":{"contentType":"text/css; charset=utf-8","body":":root {\n  --bg: #eef1f4;\n  --ink: #182028;\n  --muted: #66727f;\n  --panel: #ffffff;\n  --panel-alt: #f6f8fa;\n  --line: #d9e0e7;\n  --strong-line: #b8c3ce;\n  --accent: #0f766e;\n  --danger: #9f1239;\n  --shadow: 0 18px 42px rgba(24, 32, 40, 0.16);\n}\n\n/* Critical Leaflet layout rules. Kept local so the map still works if the CDN stylesheet is blocked. */\n.leaflet-pane,\n.leaflet-tile,\n.leaflet-marker-icon,\n.leaflet-marker-shadow,\n.leaflet-tile-container,\n.leaflet-pane > svg,\n.leaflet-pane > canvas,\n.leaflet-zoom-box,\n.leaflet-image-layer,\n.leaflet-layer {\n  position: absolute;\n  left: 0;\n  top: 0;\n}\n\n.leaflet-container {\n  overflow: hidden;\n  position: relative;\n  z-index: 0;\n  -webkit-tap-highlight-color: transparent;\n  background: #d9e2e5;\n  outline-offset: 1px;\n}\n\n.leaflet-map-pane {\n  z-index: 400;\n}\n\n.leaflet-tile-pane {\n  z-index: 200;\n}\n\n.leaflet-overlay-pane {\n  z-index: 400;\n}\n\n.leaflet-shadow-pane {\n  z-index: 500;\n}\n\n.leaflet-marker-pane {\n  z-index: 600;\n}\n\n.leaflet-tooltip-pane {\n  z-index: 650;\n}\n\n.leaflet-popup-pane {\n  z-index: 700;\n}\n\n.leaflet-tile,\n.leaflet-marker-icon,\n.leaflet-marker-shadow {\n  max-width: none;\n  max-height: none;\n  user-select: none;\n  -webkit-user-drag: none;\n}\n\n.leaflet-container img,\n.leaflet-container svg {\n  max-width: none;\n  max-height: none;\n}\n\n.leaflet-tile {\n  filter: inherit;\n  visibility: hidden;\n}\n\n.leaflet-tile-loaded {\n  visibility: inherit;\n}\n\n.leaflet-zoom-animated {\n  transform-origin: 0 0;\n}\n\n.leaflet-interactive {\n  cursor: pointer;\n}\n\n.leaflet-grab {\n  cursor: grab;\n}\n\n.leaflet-dragging .leaflet-grab,\n.leaflet-dragging .leaflet-interactive {\n  cursor: grabbing;\n}\n\n.leaflet-control {\n  position: relative;\n  z-index: 800;\n  pointer-events: auto;\n}\n\n.leaflet-top,\n.leaflet-bottom {\n  position: absolute;\n  z-index: 1000;\n  pointer-events: none;\n}\n\n.leaflet-top {\n  top: 0;\n}\n\n.leaflet-right {\n  right: 0;\n}\n\n.leaflet-bottom {\n  bottom: 0;\n}\n\n.leaflet-left {\n  left: 0;\n}\n\n.leaflet-top .leaflet-control {\n  margin-top: 10px;\n}\n\n.leaflet-bottom .leaflet-control {\n  margin-bottom: 10px;\n}\n\n.leaflet-left .leaflet-control {\n  margin-left: 10px;\n}\n\n.leaflet-right .leaflet-control {\n  margin-right: 10px;\n}\n\n.leaflet-control-zoom {\n  border: 1px solid rgba(24, 32, 40, 0.15);\n  border-radius: 8px;\n  overflow: hidden;\n  box-shadow: 0 8px 22px rgba(24, 32, 40, 0.16);\n}\n\n.leaflet-control-zoom a {\n  display: block;\n  width: 32px;\n  height: 32px;\n  background: #fff;\n  color: #182028;\n  font-size: 20px;\n  font-weight: 760;\n  line-height: 30px;\n  text-align: center;\n  text-decoration: none;\n}\n\n.leaflet-control-zoom a + a {\n  border-top: 1px solid var(--line);\n}\n\n.leaflet-control-attribution {\n  margin: 0;\n  background: rgba(255, 255, 255, 0.82);\n  color: #475569;\n  font-size: 10px;\n  padding: 2px 6px;\n}\n\n.leaflet-popup {\n  position: absolute;\n  margin-bottom: 20px;\n  text-align: center;\n}\n\n.leaflet-popup-content-wrapper {\n  border-radius: 8px;\n  background: #fff;\n  box-shadow: 0 10px 30px rgba(24, 32, 40, 0.2);\n  padding: 1px;\n  text-align: left;\n}\n\n.leaflet-popup-content {\n  margin: 12px 14px;\n  line-height: 1.35;\n}\n\n.leaflet-popup-tip-container {\n  position: absolute;\n  left: 50%;\n  width: 40px;\n  height: 20px;\n  margin-left: -20px;\n  overflow: hidden;\n  pointer-events: none;\n}\n\n.leaflet-popup-tip {\n  width: 15px;\n  height: 15px;\n  margin: -8px auto 0;\n  background: #fff;\n  box-shadow: 0 10px 30px rgba(24, 32, 40, 0.18);\n  transform: rotate(45deg);\n}\n\n.leaflet-popup-close-button {\n  position: absolute;\n  top: 4px;\n  right: 6px;\n  color: #66727f;\n  font: 18px/18px Arial, Helvetica, sans-serif;\n  text-decoration: none;\n}\n\n.leaflet-div-icon {\n  border: 0;\n  background: transparent;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nhtml,\nbody {\n  height: 100%;\n}\n\nbody {\n  margin: 0;\n  background: var(--bg);\n  color: var(--ink);\n  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n}\n\nbutton,\nselect,\ntextarea {\n  font: inherit;\n}\n\nbutton {\n  cursor: pointer;\n}\n\n.app-shell {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) 390px;\n  height: 100vh;\n  min-height: 650px;\n}\n\n.map-stage {\n  position: relative;\n  min-width: 0;\n}\n\n#map {\n  width: 100%;\n  height: 100%;\n  background: #d9e2e5;\n}\n\n.map-topbar {\n  position: absolute;\n  z-index: 500;\n  top: 16px;\n  left: 16px;\n  right: 16px;\n  display: flex;\n  align-items: flex-start;\n  justify-content: space-between;\n  gap: 12px;\n  pointer-events: none;\n}\n\n.brand-block {\n  max-width: min(430px, 72vw);\n  border: 1px solid rgba(217, 224, 231, 0.9);\n  border-radius: 8px;\n  background: rgba(255, 255, 255, 0.94);\n  box-shadow: var(--shadow);\n  padding: 12px 14px 13px;\n  pointer-events: auto;\n}\n\n.brand-block p {\n  margin: 0 0 4px;\n  color: var(--muted);\n  font-size: 11px;\n  font-weight: 760;\n  letter-spacing: 0;\n  text-transform: uppercase;\n}\n\nh1 {\n  margin: 0;\n  font-size: 25px;\n  line-height: 1.08;\n}\n\n.map-actions {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  pointer-events: auto;\n}\n\n.icon-button,\n.text-button,\n.primary-button {\n  min-height: 36px;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: #fff;\n  color: var(--ink);\n}\n\n.icon-button {\n  display: grid;\n  width: 36px;\n  place-items: center;\n  font-size: 19px;\n  line-height: 1;\n}\n\n.text-button {\n  padding: 0 12px;\n  font-size: 13px;\n  font-weight: 760;\n}\n\n.text-button.is-active {\n  border-color: #0b665f;\n  background: #0f766e;\n  color: #fff;\n}\n\n.text-button.muted {\n  min-height: 32px;\n  background: var(--panel-alt);\n}\n\n.primary-button {\n  width: 100%;\n  border-color: #0b665f;\n  background: #0f766e;\n  color: #fff;\n  font-size: 13px;\n  font-weight: 800;\n}\n\n.control-panel {\n  display: flex;\n  flex-direction: column;\n  min-height: 0;\n  border-left: 1px solid var(--line);\n  background: var(--panel);\n  box-shadow: -14px 0 38px rgba(24, 32, 40, 0.08);\n}\n\n.panel-section {\n  border-bottom: 1px solid var(--line);\n  padding: 16px;\n}\n\n.section-heading {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 14px;\n  margin-bottom: 12px;\n  color: var(--ink);\n  font-size: 12px;\n  font-weight: 820;\n  text-transform: uppercase;\n}\n\n.section-heading.compact {\n  margin-bottom: 8px;\n}\n\n.section-heading strong {\n  min-width: 28px;\n  border-radius: 999px;\n  background: #e8f2f1;\n  color: #0d4f49;\n  padding: 4px 8px;\n  text-align: center;\n}\n\n.filter-list {\n  display: grid;\n  gap: 8px;\n}\n\n.zone-toggle {\n  display: grid;\n  grid-template-columns: 18px 14px minmax(0, 1fr) auto;\n  align-items: center;\n  gap: 9px;\n  min-height: 48px;\n  padding: 9px;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: #fbfcfd;\n}\n\n.zone-toggle.is-selected {\n  border-color: var(--zone-color);\n  box-shadow: inset 3px 0 0 var(--zone-color);\n}\n\n.zone-toggle input {\n  margin: 0;\n  accent-color: var(--zone-color);\n}\n\n.zone-swatch {\n  width: 14px;\n  height: 14px;\n  border-radius: 4px;\n  background: var(--zone-color);\n  box-shadow: inset 0 0 0 1px rgba(0, 0, 0, 0.18);\n}\n\n.zone-text {\n  display: grid;\n  min-width: 0;\n}\n\n.zone-text strong {\n  overflow: hidden;\n  color: var(--ink);\n  font-size: 14px;\n  line-height: 1.2;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.zone-text small {\n  overflow: hidden;\n  color: var(--muted);\n  font-size: 12px;\n  line-height: 1.35;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.zone-edit-button {\n  width: 30px;\n  height: 30px;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: var(--panel-alt);\n  color: var(--ink);\n  font-size: 14px;\n}\n\n.select-label {\n  display: block;\n  margin-bottom: 8px;\n  color: var(--ink);\n  font-size: 13px;\n  font-weight: 760;\n}\n\nselect {\n  width: 100%;\n  height: 40px;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: #fff;\n  color: var(--ink);\n  padding: 0 10px;\n}\n\n.hint {\n  margin-top: 8px;\n  color: var(--muted);\n  font-size: 12px;\n  line-height: 1.4;\n}\n\n.editor-panel {\n  min-height: 220px;\n}\n\ntextarea {\n  display: block;\n  width: 100%;\n  min-height: 128px;\n  resize: vertical;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: #fbfcfd;\n  color: #15202b;\n  font-family: \"SFMono-Regular\", Consolas, \"Liberation Mono\", monospace;\n  font-size: 11px;\n  line-height: 1.45;\n  padding: 10px;\n}\n\n.editor-status {\n  min-height: 18px;\n  margin-top: 8px;\n  color: var(--muted);\n  font-size: 12px;\n}\n\n.editor-status.is-error {\n  color: var(--danger);\n  font-weight: 700;\n}\n\n.switch-row,\n.metric-row {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 12px;\n  min-height: 36px;\n  color: var(--ink);\n  font-size: 13px;\n}\n\n.switch-row + .switch-row,\n.metric-row + .metric-row {\n  border-top: 1px solid var(--line);\n}\n\n.switch-row input {\n  margin: 0;\n  accent-color: var(--accent);\n}\n\n.switch-row span {\n  flex: 1;\n}\n\n.summary-panel strong {\n  color: #22313d;\n  font-size: 12px;\n  text-align: right;\n  text-transform: uppercase;\n}\n\n.panel-footer {\n  margin-top: auto;\n  border-top: 1px solid var(--line);\n  background: var(--panel-alt);\n  padding: 16px;\n}\n\n.panel-footer p {\n  margin: 10px 0 0;\n  color: var(--muted);\n  font-size: 12px;\n  line-height: 1.38;\n}\n\n.zone-label {\n  border: 0;\n  background: transparent;\n}\n\n.zone-label span {\n  display: block;\n  border: 1px solid rgba(255, 255, 255, 0.85);\n  border-radius: 999px;\n  background: rgba(24, 32, 40, 0.78);\n  color: #fff;\n  font-size: 11px;\n  font-weight: 800;\n  line-height: 1;\n  padding: 5px 8px;\n  white-space: nowrap;\n}\n\n.vertex-handle {\n  display: block;\n  width: 14px;\n  height: 14px;\n  border: 2px solid #fff;\n  border-radius: 50%;\n  background: var(--handle-color);\n  box-shadow: 0 2px 10px rgba(24, 32, 40, 0.36);\n}\n\n.reference-marker {\n  display: block;\n  width: 16px;\n  height: 16px;\n  border: 3px solid #fff;\n  border-radius: 50%;\n  background: #25313b;\n  box-shadow: 0 2px 10px rgba(24, 32, 40, 0.32);\n}\n\n.popup-card {\n  display: grid;\n  gap: 4px;\n  min-width: 190px;\n}\n\n.popup-card strong {\n  font-size: 14px;\n}\n\n.popup-card span,\n.popup-card em {\n  color: #4f5c57;\n  font-size: 12px;\n}\n\n.excluded-area {\n  color: #4b5563;\n  font-size: 12px;\n}\n\n.leaflet-control-attribution {\n  font-size: 10px;\n}\n\n@media (max-width: 900px) {\n  .app-shell {\n    grid-template-columns: 1fr;\n    grid-template-rows: minmax(430px, 58vh) minmax(0, 1fr);\n    height: auto;\n    min-height: 100vh;\n  }\n\n  .control-panel {\n    border-top: 1px solid var(--line);\n    border-left: 0;\n  }\n\n  .map-topbar {\n    flex-direction: column;\n    align-items: flex-start;\n  }\n\n  h1 {\n    font-size: 22px;\n  }\n}\n\n@media (max-width: 520px) {\n  .map-topbar {\n    top: 10px;\n    left: 10px;\n    right: 10px;\n  }\n\n  .brand-block {\n    max-width: calc(100vw - 20px);\n  }\n\n  .map-actions {\n    width: 100%;\n  }\n\n  .text-button {\n    flex: 1;\n  }\n\n  .app-shell {\n    grid-template-rows: minmax(410px, 55vh) minmax(0, 1fr);\n  }\n}\n"},"/data.js":{"contentType":"application/javascript; charset=utf-8","body":"window.EMBOLSADO_MAP_DATA = {\n  generatedAt: \"2026-06-18\",\n  company: \"Lagomarsino S.A.\",\n  channel: \"Embolsado\",\n  notes: {\n    capitalFederal: \"Capital Federal queda excluida de esta primera version.\",\n    sales: \"No hay ventas cargadas todavia.\",\n    clients: \"Los clientes reales geolocalizados se cargaran luego desde Exceles actuales.\"\n  },\n  territoryAssignment: {\n    rule: \"specific-zones-first\",\n    priority: [\"amba-norte\", \"amba-oeste\", \"amba-sur\", \"interior\"],\n    fallbackZoneId: \"interior\",\n    excludedZoneIds: [\"capital-federal\"]\n  },\n  cabaExclusion: {\n    name: \"Capital Federal\",\n    color: \"#6b7280\",\n    coordinates: [\n      [-34.534, -58.535],\n      [-34.548, -58.458],\n      [-34.566, -58.374],\n      [-34.594, -58.335],\n      [-34.631, -58.347],\n      [-34.667, -58.381],\n      [-34.694, -58.459],\n      [-34.665, -58.529],\n      [-34.615, -58.532],\n      [-34.566, -58.548]\n    ]\n  },\n  initialBounds: [\n    [-35.08, -59.1],\n    [-34.3, -58.02]\n  ],\n  zones: [\n    {\n      id: \"amba-norte\",\n      name: \"AMBA Norte\",\n      manager: \"Jefe de Venta AMBA Norte\",\n      color: \"#047857\",\n      defaultVisible: true,\n      description: \"Zona tentativa de GBA norte hasta Zarate, sin Capital Federal.\",\n      labelPosition: [-34.35, -58.82],\n      coordinates: [\n        [-34.548, -58.458],\n        [-34.515, -58.43],\n        [-34.415, -58.465],\n        [-34.245, -58.63],\n        [-34.095, -59.025],\n        [-34.235, -59.16],\n        [-34.43, -59.045],\n        [-34.56, -58.985],\n        [-34.61, -58.735],\n        [-34.566, -58.548]\n      ]\n    },\n    {\n      id: \"amba-oeste\",\n      name: \"AMBA Oeste\",\n      manager: \"Jefe de Venta AMBA Oeste\",\n      color: \"#2563eb\",\n      defaultVisible: true,\n      description: \"Zona tentativa de GBA oeste, sin Capital Federal.\",\n      labelPosition: [-34.69, -58.82],\n      coordinates: [\n        [-34.566, -58.548],\n        [-34.61, -58.735],\n        [-34.56, -58.985],\n        [-34.64, -59.18],\n        [-34.81, -59.16],\n        [-34.91, -58.89],\n        [-34.82, -58.64],\n        [-34.665, -58.529]\n      ]\n    },\n    {\n      id: \"amba-sur\",\n      name: \"AMBA Sur\",\n      manager: \"Jefe de Venta AMBA Sur\",\n      color: \"#dc2626\",\n      defaultVisible: true,\n      description: \"Zona tentativa de GBA sur incluyendo La Plata, sin Capital Federal.\",\n      labelPosition: [-34.9, -58.28],\n      coordinates: [\n        [-34.665, -58.529],\n        [-34.82, -58.64],\n        [-35.02, -58.64],\n        [-35.14, -58.34],\n        [-35.06, -58.02],\n        [-34.92, -57.87],\n        [-34.78, -58.02],\n        [-34.68, -58.22],\n        [-34.631, -58.347],\n        [-34.694, -58.459]\n      ]\n    },\n    {\n      id: \"interior\",\n      name: \"Interior\",\n      manager: \"Jefe de Venta Interior\",\n      color: \"#7c3aed\",\n      defaultVisible: true,\n      description: \"Resto del pais para analizar ventas fuera de AMBA.\",\n      labelPosition: [-32.9, -63.8],\n      coordinates: [\n        [\n          [-21.78, -66.22],\n          [-22.1, -62.2],\n          [-24.05, -59.15],\n          [-25.65, -57.74],\n          [-27.28, -55.55],\n          [-30.18, -57.63],\n          [-33.65, -58.42],\n          [-35.25, -57.1],\n          [-37.0, -56.75],\n          [-38.15, -57.45],\n          [-39.25, -61.8],\n          [-40.9, -62.75],\n          [-42.85, -64.05],\n          [-46.02, -66.25],\n          [-49.3, -67.05],\n          [-52.35, -67.55],\n          [-55.05, -67.15],\n          [-54.86, -70.88],\n          [-51.62, -73.28],\n          [-48.88, -73.58],\n          [-45.8, -71.72],\n          [-42.26, -71.78],\n          [-39.15, -71.13],\n          [-36.62, -70.33],\n          [-34.18, -69.86],\n          [-31.95, -69.22],\n          [-29.25, -68.65],\n          [-26.52, -68.34],\n          [-24.12, -67.32],\n          [-21.78, -66.22]\n        ],\n        [\n          [-34.0, -59.28],\n          [-34.0, -57.72],\n          [-35.28, -57.72],\n          [-35.28, -59.28],\n          [-34.0, -59.28]\n        ]\n      ]\n    }\n  ],\n  referencePoints: [\n    {\n      name: \"GBA Norte\",\n      lat: -34.47,\n      lng: -58.63,\n      detail: \"Referencia territorial, no cliente.\"\n    },\n    {\n      name: \"GBA Oeste\",\n      lat: -34.68,\n      lng: -58.73,\n      detail: \"Referencia territorial, no cliente.\"\n    },\n    {\n      name: \"GBA Sur\",\n      lat: -34.83,\n      lng: -58.36,\n      detail: \"Referencia territorial, no cliente.\"\n    },\n    {\n      name: \"Rosario\",\n      lat: -32.9442,\n      lng: -60.6505,\n      detail: \"Referencia territorial, no cliente.\"\n    },\n    {\n      name: \"Cordoba\",\n      lat: -31.4201,\n      lng: -64.1888,\n      detail: \"Referencia territorial, no cliente.\"\n    },\n    {\n      name: \"Mendoza\",\n      lat: -32.8895,\n      lng: -68.8458,\n      detail: \"Referencia territorial, no cliente.\"\n    },\n    {\n      name: \"Mar del Plata\",\n      lat: -38.0055,\n      lng: -57.5426,\n      detail: \"Referencia territorial, no cliente.\"\n    }\n  ]\n};\n"},"/app.js":{"contentType":"application/javascript; charset=utf-8","body":"const data = window.EMBOLSADO_MAP_DATA;\nconst zones = data.zones;\n\nconst zoneById = new Map(zones.map((zone) => [zone.id, zone]));\nconst visibleZones = new Set(zones.filter((zone) => zone.defaultVisible).map((zone) => zone.id));\nlet selectedZoneId = zones[0].id;\nlet editing = false;\nlet showCaba = true;\nlet showReference = true;\n\nconst map = L.map(\"map\", {\n  zoomControl: false,\n  preferCanvas: true\n}).setView([-34.72, -58.64], 9);\n\nL.control.zoom({ position: \"bottomleft\" }).addTo(map);\n\nL.tileLayer(\"https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png\", {\n  maxZoom: 18,\n  attribution: \"&copy; OpenStreetMap\"\n}).addTo(map);\n\nconst zoneLayer = L.layerGroup().addTo(map);\nconst labelLayer = L.layerGroup().addTo(map);\nconst cabaLayer = L.layerGroup().addTo(map);\nconst referenceLayer = L.layerGroup().addTo(map);\nconst editLayer = L.layerGroup().addTo(map);\n\nconst zoneFilters = document.getElementById(\"zone-filters\");\nconst zoneSelect = document.getElementById(\"zone-editor-select\");\nconst coordinatesEditor = document.getElementById(\"coordinates-editor\");\nconst editorStatus = document.getElementById(\"editor-status\");\nconst fitMapButton = document.getElementById(\"fit-map\");\nconst toggleEditButton = document.getElementById(\"toggle-edit\");\nconst applyCoordinatesButton = document.getElementById(\"apply-coordinates\");\nconst copyConfigButton = document.getElementById(\"copy-config\");\nconst toggleCaba = document.getElementById(\"toggle-caba\");\nconst toggleReference = document.getElementById(\"toggle-reference\");\n\nfunction isNestedCoordinates(coordinates) {\n  return Array.isArray(coordinates[0]?.[0]);\n}\n\nfunction cloneCoordinates(coordinates) {\n  return JSON.parse(JSON.stringify(coordinates));\n}\n\nfunction getRings(zone) {\n  return isNestedCoordinates(zone.coordinates) ? zone.coordinates : [zone.coordinates];\n}\n\nfunction getOuterRing(zone) {\n  return getRings(zone)[0];\n}\n\nfunction setCoordinates(zone, nextCoordinates) {\n  zone.coordinates = cloneCoordinates(nextCoordinates);\n  if (!isNestedCoordinates(zone.coordinates)) {\n    zone.labelPosition = estimateCenter(zone.coordinates);\n  }\n}\n\nfunction estimateCenter(ring) {\n  const totals = ring.reduce(\n    (acc, point) => {\n      acc.lat += point[0];\n      acc.lng += point[1];\n      return acc;\n    },\n    { lat: 0, lng: 0 }\n  );\n  return [totals.lat / ring.length, totals.lng / ring.length];\n}\n\nfunction validateCoordinates(value) {\n  if (!Array.isArray(value) || value.length < 3) {\n    throw new Error(\"La zona necesita al menos 3 puntos o anillos.\");\n  }\n\n  const rings = isNestedCoordinates(value) ? value : [value];\n  rings.forEach((ring) => {\n    if (!Array.isArray(ring) || ring.length < 3) {\n      throw new Error(\"Cada anillo necesita al menos 3 puntos.\");\n    }\n    ring.forEach((point) => {\n      if (!Array.isArray(point) || point.length !== 2) {\n        throw new Error(\"Cada punto debe ser [lat, lng].\");\n      }\n      const [lat, lng] = point;\n      if (!Number.isFinite(lat) || !Number.isFinite(lng)) {\n        throw new Error(\"Latitud y longitud deben ser numeros.\");\n      }\n    });\n  });\n}\n\nfunction setStatus(message, isError = false) {\n  editorStatus.textContent = message;\n  editorStatus.classList.toggle(\"is-error\", isError);\n}\n\nfunction polygonShape(zone) {\n  return cloneCoordinates(zone.coordinates);\n}\n\nfunction zoneStyle(zone) {\n  return {\n    color: zone.color,\n    weight: zone.id === selectedZoneId ? 3 : 2,\n    opacity: 0.95,\n    fillColor: zone.color,\n    fillOpacity: zone.id === \"interior\" ? 0.07 : 0.18,\n    dashArray: zone.id === \"interior\" ? \"7 8\" : null\n  };\n}\n\nfunction renderZones() {\n  zoneLayer.clearLayers();\n  labelLayer.clearLayers();\n\n  zones\n    .filter((zone) => visibleZones.has(zone.id))\n    .sort((a, b) => {\n      if (a.id === \"interior\") return -1;\n      if (b.id === \"interior\") return 1;\n      return 0;\n    })\n    .forEach((zone) => {\n      const polygon = L.polygon(polygonShape(zone), zoneStyle(zone)).bindPopup(`\n        <div class=\"popup-card\">\n          <strong>${zone.name}</strong>\n          <span>${zone.manager}</span>\n          <em>${zone.description}</em>\n        </div>\n      `);\n\n      polygon.on(\"click\", () => selectZone(zone.id));\n      zoneLayer.addLayer(polygon);\n\n      L.marker(zone.labelPosition || estimateCenter(getOuterRing(zone)), {\n        interactive: false,\n        icon: L.divIcon({\n          className: \"zone-label\",\n          html: `<span>${zone.name}</span>`,\n          iconSize: [90, 24],\n          iconAnchor: [45, 12]\n        })\n      }).addTo(labelLayer);\n    });\n}\n\nfunction renderCaba() {\n  cabaLayer.clearLayers();\n  if (!showCaba) return;\n\n  L.polygon(data.cabaExclusion.coordinates, {\n    color: data.cabaExclusion.color,\n    weight: 2,\n    opacity: 0.95,\n    fillColor: data.cabaExclusion.color,\n    fillOpacity: 0.16,\n    dashArray: \"3 6\"\n  })\n    .bindPopup(`<strong>${data.cabaExclusion.name}</strong><br><span class=\"excluded-area\">Excluida de esta primera version.</span>`)\n    .addTo(cabaLayer);\n}\n\nfunction renderReferencePoints() {\n  referenceLayer.clearLayers();\n  if (!showReference) return;\n\n  data.referencePoints.forEach((point) => {\n    L.marker([point.lat, point.lng], {\n      icon: L.divIcon({\n        className: \"reference-marker-wrap\",\n        html: '<span class=\"reference-marker\"></span>',\n        iconSize: [16, 16],\n        iconAnchor: [8, 8],\n        popupAnchor: [0, -8]\n      })\n    })\n      .bindPopup(`\n        <div class=\"popup-card\">\n          <strong>${point.name}</strong>\n          <span>${point.detail}</span>\n        </div>\n      `)\n      .addTo(referenceLayer);\n  });\n}\n\nfunction renderZoneControls() {\n  zoneFilters.innerHTML = \"\";\n\n  zones.forEach((zone) => {\n    const row = document.createElement(\"div\");\n    row.className = `zone-toggle ${zone.id === selectedZoneId ? \"is-selected\" : \"\"}`;\n    row.style.setProperty(\"--zone-color\", zone.color);\n\n    const input = document.createElement(\"input\");\n    input.type = \"checkbox\";\n    input.setAttribute(\"aria-label\", `Mostrar ${zone.name}`);\n    input.checked = visibleZones.has(zone.id);\n    input.addEventListener(\"click\", (event) => {\n      event.stopPropagation();\n    });\n    input.addEventListener(\"change\", (event) => {\n      event.stopPropagation();\n      if (input.checked) visibleZones.add(zone.id);\n      else visibleZones.delete(zone.id);\n      render();\n    });\n\n    const color = document.createElement(\"span\");\n    color.className = \"zone-swatch\";\n\n    const text = document.createElement(\"span\");\n    text.className = \"zone-text\";\n    text.innerHTML = `<strong>${zone.name}</strong><small>${zone.manager}</small>`;\n\n    const button = document.createElement(\"button\");\n    button.className = \"zone-edit-button\";\n    button.type = \"button\";\n    button.title = `Editar ${zone.name}`;\n    button.textContent = \"✎\";\n    button.addEventListener(\"click\", (event) => {\n      event.preventDefault();\n      event.stopPropagation();\n      selectZone(zone.id);\n      editing = true;\n      render();\n    });\n\n    row.addEventListener(\"click\", () => selectZone(zone.id));\n    row.append(input, color, text, button);\n    zoneFilters.appendChild(row);\n  });\n}\n\nfunction fillZoneSelect() {\n  zoneSelect.innerHTML = \"\";\n  zones.forEach((zone) => {\n    const option = document.createElement(\"option\");\n    option.value = zone.id;\n    option.textContent = zone.name;\n    zoneSelect.appendChild(option);\n  });\n}\n\nfunction updateEditor() {\n  const zone = zoneById.get(selectedZoneId);\n  zoneSelect.value = selectedZoneId;\n  coordinatesEditor.value = JSON.stringify(zone.coordinates, null, 2);\n}\n\nfunction renderEditHandles() {\n  editLayer.clearLayers();\n  toggleEditButton.classList.toggle(\"is-active\", editing);\n  toggleEditButton.textContent = editing ? \"Edicion activa\" : \"Editar zonas\";\n\n  if (!editing) return;\n\n  const zone = zoneById.get(selectedZoneId);\n  const rings = getRings(zone);\n\n  rings.forEach((ring, ringIndex) => {\n    ring.forEach((point, pointIndex) => {\n      const marker = L.marker(point, {\n        draggable: true,\n        icon: L.divIcon({\n          className: \"vertex-handle-wrap\",\n          html: `<span class=\"vertex-handle\" style=\"--handle-color:${zone.color}\"></span>`,\n          iconSize: [14, 14],\n          iconAnchor: [7, 7]\n        })\n      });\n\n      marker.on(\"drag\", () => {\n        const latLng = marker.getLatLng();\n        rings[ringIndex][pointIndex] = [\n          Number(latLng.lat.toFixed(5)),\n          Number(latLng.lng.toFixed(5))\n        ];\n        zone.coordinates = isNestedCoordinates(zone.coordinates) ? rings : rings[0];\n        if (!isNestedCoordinates(zone.coordinates)) {\n          zone.labelPosition = estimateCenter(zone.coordinates);\n        }\n        updateEditor();\n        renderZones();\n        setStatus(\"Cambios aplicados en el mapa. Copia el JSON para conservarlos.\");\n      });\n\n      marker.addTo(editLayer);\n    });\n  });\n}\n\nfunction selectZone(zoneId) {\n  selectedZoneId = zoneId;\n  updateEditor();\n  render();\n}\n\nfunction applyCoordinates() {\n  const zone = zoneById.get(selectedZoneId);\n\n  try {\n    const nextCoordinates = JSON.parse(coordinatesEditor.value);\n    validateCoordinates(nextCoordinates);\n    setCoordinates(zone, nextCoordinates);\n    setStatus(\"Coordenadas aplicadas.\");\n    render();\n    fitVisible(false);\n  } catch (error) {\n    setStatus(error.message, true);\n  }\n}\n\nasync function copyConfig() {\n  const payload = {\n    generatedAt: data.generatedAt,\n    company: data.company,\n    channel: data.channel,\n    zones: zones.map((zone) => ({\n      id: zone.id,\n      name: zone.name,\n      manager: zone.manager,\n      color: zone.color,\n      description: zone.description,\n      labelPosition: zone.labelPosition,\n      coordinates: zone.coordinates\n    }))\n  };\n\n  const text = JSON.stringify(payload, null, 2);\n\n  try {\n    await navigator.clipboard.writeText(text);\n    setStatus(\"Configuracion copiada al portapapeles.\");\n  } catch {\n    coordinatesEditor.value = text;\n    setStatus(\"No se pudo copiar. Deje el JSON completo en el editor.\");\n  }\n}\n\nfunction fitVisible(includeInterior = true) {\n  const points = [];\n\n  zones\n    .filter((zone) => visibleZones.has(zone.id))\n    .filter((zone) => includeInterior || zone.id !== \"interior\")\n    .forEach((zone) => {\n      getRings(zone).forEach((ring) => points.push(...ring));\n    });\n\n  if (points.length) {\n    map.fitBounds(points, { padding: [48, 48], maxZoom: includeInterior ? 5 : 10 });\n  }\n}\n\nfunction fitInitialView() {\n  if (Array.isArray(data.initialBounds)) {\n    map.fitBounds(data.initialBounds, { padding: [48, 48], maxZoom: 10 });\n    return;\n  }\n\n  fitVisible(false);\n}\n\nfunction render() {\n  renderZoneControls();\n  renderZones();\n  renderCaba();\n  renderReferencePoints();\n  renderEditHandles();\n}\n\nzoneSelect.addEventListener(\"change\", () => selectZone(zoneSelect.value));\nfitMapButton.addEventListener(\"click\", fitInitialView);\ntoggleEditButton.addEventListener(\"click\", () => {\n  editing = !editing;\n  render();\n});\napplyCoordinatesButton.addEventListener(\"click\", applyCoordinates);\ncopyConfigButton.addEventListener(\"click\", copyConfig);\ntoggleCaba.addEventListener(\"change\", () => {\n  showCaba = toggleCaba.checked;\n  renderCaba();\n});\ntoggleReference.addEventListener(\"change\", () => {\n  showReference = toggleReference.checked;\n  renderReferencePoints();\n});\n\nfillZoneSelect();\nupdateEditor();\nrender();\nfitInitialView();\n\nrequestAnimationFrame(() => {\n  map.invalidateSize();\n  fitInitialView();\n});\n\nwindow.addEventListener(\"resize\", () => {\n  map.invalidateSize();\n});\n"},"/":{"contentType":"text/html; charset=utf-8","body":"<!doctype html>\n<html lang=\"es\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title>Lagomarsino S.A. - Mapa Comercial Embolsado</title>\n    <link rel=\"stylesheet\" href=\"/styles.css?v=20260618-7\" />\n  </head>\n  <body>\n    <main class=\"app-shell\">\n      <section class=\"map-stage\" aria-label=\"Mapa comercial Embolsado\">\n        <div id=\"map\"></div>\n        <div class=\"map-topbar\">\n          <div class=\"brand-block\">\n            <p>Lagomarsino S.A. / Canal Embolsado</p>\n            <h1>Mapa Comercial</h1>\n          </div>\n          <div class=\"map-actions\" aria-label=\"Acciones del mapa\">\n            <button id=\"fit-map\" class=\"icon-button\" type=\"button\" title=\"Ver AMBA\">⌖</button>\n            <button id=\"toggle-edit\" class=\"text-button\" type=\"button\">Editar zonas</button>\n          </div>\n        </div>\n      </section>\n\n      <aside class=\"control-panel\" aria-label=\"Panel territorial\">\n        <section class=\"panel-section\">\n          <div class=\"section-heading\">\n            <span>Zonas tentativas</span>\n            <strong>4</strong>\n          </div>\n          <div id=\"zone-filters\" class=\"filter-list\"></div>\n        </section>\n\n        <section class=\"panel-section\">\n          <label class=\"select-label\" for=\"zone-editor-select\">Zona a editar</label>\n          <select id=\"zone-editor-select\"></select>\n          <div class=\"hint\">\n            Arrastra vertices en el mapa o pega coordenadas JSON. Despues copia la configuracion para conservar los cambios.\n          </div>\n        </section>\n\n        <section class=\"panel-section editor-panel\">\n          <div class=\"section-heading compact\">\n            <span>Coordenadas</span>\n            <button id=\"apply-coordinates\" class=\"text-button muted\" type=\"button\">Aplicar</button>\n          </div>\n          <textarea id=\"coordinates-editor\" spellcheck=\"false\"></textarea>\n          <div id=\"editor-status\" class=\"editor-status\">Editor listo.</div>\n        </section>\n\n        <section class=\"panel-section\">\n          <div class=\"section-heading compact\">\n            <span>Capas</span>\n          </div>\n          <label class=\"switch-row\">\n            <input id=\"toggle-caba\" type=\"checkbox\" checked />\n            <span>Mostrar Capital Federal excluida</span>\n          </label>\n          <label class=\"switch-row\">\n            <input id=\"toggle-reference\" type=\"checkbox\" checked />\n            <span>Mostrar puntos de referencia</span>\n          </label>\n        </section>\n\n        <section class=\"panel-section summary-panel\">\n          <div class=\"metric-row\">\n            <span>Clientes</span>\n            <strong>pendiente Excel</strong>\n          </div>\n          <div class=\"metric-row\">\n            <span>Ventas</span>\n            <strong>no cargadas</strong>\n          </div>\n          <div class=\"metric-row\">\n            <span>CABA</span>\n            <strong>excluida</strong>\n          </div>\n        </section>\n\n        <div class=\"panel-footer\">\n          <button id=\"copy-config\" class=\"primary-button\" type=\"button\">Copiar zonas JSON</button>\n          <p>Primera version territorial: AMBA sin Capital Federal e Interior. Preparada para sumar clientes geolocalizados y ventas mas adelante.</p>\n        </div>\n      </aside>\n    </main>\n\n    <script\n      src=\"https://unpkg.com/leaflet@1.9.4/dist/leaflet.js\"\n      integrity=\"sha256-20nQCchB9co0qIjJZRGuk2/Z9VM+kNiyxNV1lvTlZBo=\"\n      crossorigin=\"\"\n    ></script>\n    <script src=\"/data.js?v=20260618-7\"></script>\n    <script src=\"/app.js?v=20260618-7\"></script>\n  </body>\n</html>\n"}};

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const pathname = url.pathname === "/" ? "/index.html" : url.pathname;
    const asset = assets[pathname];

    if (asset) {
      return new Response(asset.body, {
        headers: {
          "content-type": asset.contentType,
          "cache-control": "no-store, max-age=0"
        }
      });
    }

    return new Response("Not found", { status: 404 });
  }
};
